// Typed auth store error — preserves partial data for recovery
class AuthStoreCorrupted {
  readonly _tag = "AuthStoreCorrupted"
  constructor(
    readonly message: string,
    readonly partialData: Record<string, unknown>,
  ) {}
}

const all = Effect.fn("McpAuth.all")(function* () {
  return yield* fs.readJson(filepath).pipe(
    Effect.flatMap((data) => {
      const result = decodeAuthData(data)
      if (Option.isNone(result)) {
        // Log warning with corruption detail but preserve whatever we can
        yield* Effect.logWarning("McpAuth: auth data corrupted, using partial data").pipe(
          Effect.annotateLogs({ file: filepath }),
        )
        // Attempt partial recovery: iterate known entries and validate individually
        if (typeof data === "object" && data !== null) {
          const partial: AuthData = {}
          for (const [key, value] of Object.entries(data as Record<string, unknown>)) {
            const entry = Schema.decodeUnknownOption(Entry)(value)
            if (Option.isSome(entry)) partial[key] = entry.value
          }
          if (Object.keys(partial).length > 0) {
            yield* Effect.logWarning("McpAuth: recovered partial auth data").pipe(
              Effect.annotateLogs({ recoveredKeys: Object.keys(partial).join(","), file: filepath }),
            )
            return Effect.succeed(partial)
          }
        }
        return Effect.succeed({} as AuthData)
      }
      return Effect.succeed(result.value)
    }),
    Effect.catch((error) => {
      yield* Effect.logWarning("McpAuth: failed to read auth file, starting fresh").pipe(
        Effect.annotateLogs({ file: filepath, error: String(error) }),
      )
      return Effect.succeed({} as AuthData)
    }),
  )
})

